import React, { useState, useEffect } from 'react';
import './CookieBanner.css';

export default function CookieBanner() {
  const [visible, setVisible] = useState(false);
  const [showManage, setShowManage] = useState(false);
  const [preferences, setPreferences] = useState({
    analytics: false,
    functional: false,
    marketing: false,
  });

  useEffect(() => {
    const consent = localStorage.getItem('ame_cookie_consent');
    if (!consent) {
      const timer = setTimeout(() => setVisible(true), 600);
      return () => clearTimeout(timer);
    }
  }, []);

  /* ── Fix do duplo clique: fecha imediatamente no state,
     sem depender da transição CSS para esconder o elemento ── */
  const dismiss = (type, prefs) => {
    localStorage.setItem(
      'ame_cookie_consent',
      JSON.stringify({ type, prefs, date: new Date().toISOString() })
    );
    setVisible(false);
    setShowManage(false);
  };

  const handleAcceptAll = () =>
    dismiss('all', { analytics: true, functional: true, marketing: true });

  const handleRejectAll = () =>
    dismiss('necessary', { analytics: false, functional: false, marketing: false });

  const handleSave = () =>
    dismiss('custom', preferences);

  const toggle = (key) =>
    setPreferences((prev) => ({ ...prev, [key]: !prev[key] }));

  if (!visible) return null;

  return (
    <div className="cb">
      <div className="cb__inner">

        {/* ── Vista principal ── */}
        {!showManage ? (
          <>
            <p className="cb__text">
              Utilizamos cookies para melhorar a experiência de navegação e identificar suas
              preferências. Você pode aceitar todos os cookies, rejeitar os não essenciais ou
              gerenciar os que serão usados. Leia mais em nossa{' '}
              <a href="/politica-de-privacidade" target="_blank" rel="noopener noreferrer">
                Política de Privacidade e cookies
              </a>.
            </p>

            <div className="cb__actions">
              <button className="cb__btn cb__btn--ghost" onClick={() => setShowManage(true)}>
                Gerenciar cookies
              </button>
              <button className="cb__btn cb__btn--outline" onClick={handleRejectAll}>
                Rejeitar não essenciais
              </button>
              <button className="cb__btn cb__btn--primary" onClick={handleAcceptAll}>
                Aceitar todos
              </button>
            </div>
          </>
        ) : (

          /* ── Vista de gerenciamento ── */
          <>
            <div className="cb__manage">
              <p className="cb__manage-title">Gerenciar preferências de cookies</p>

              <div className="cb__toggles">
                {/* Essenciais — sempre ativo */}
                <div className="cb__row">
                  <div className="cb__row-info">
                    <span className="cb__row-label">Cookies essenciais</span>
                    <span className="cb__row-desc">
                      Necessários para o funcionamento básico do site. Não podem ser desativados.
                    </span>
                  </div>
                  <span className="cb__always">Sempre ativo</span>
                </div>

                {[
                  { key: 'analytics',  label: 'Cookies analíticos',  desc: 'Métricas de tráfego e comportamento (ex: Google Analytics).' },
                  { key: 'functional', label: 'Cookies funcionais',  desc: 'Funcionalidades aprimoradas como chat e formulários inteligentes.' },
                  { key: 'marketing',  label: 'Cookies de marketing', desc: 'Anúncios personalizados e rastreamento de campanhas.' },
                ].map(({ key, label, desc }) => (
                  <div key={key} className="cb__row">
                    <div className="cb__row-info">
                      <span className="cb__row-label">{label}</span>
                      <span className="cb__row-desc">{desc}</span>
                    </div>
                    <button
                      className={`cb__switch ${preferences[key] ? 'cb__switch--on' : ''}`}
                      onClick={() => toggle(key)}
                      aria-pressed={preferences[key]}
                      aria-label={`${label} ${preferences[key] ? 'ativo' : 'inativo'}`}
                    >
                      <span className="cb__thumb" />
                    </button>
                  </div>
                ))}
              </div>
            </div>

            <div className="cb__actions">
              <button className="cb__btn cb__btn--ghost" onClick={() => setShowManage(false)}>
                ← Voltar
              </button>
              <button className="cb__btn cb__btn--outline" onClick={handleRejectAll}>
                Rejeitar não essenciais
              </button>
              <button className="cb__btn cb__btn--outline" onClick={handleSave}>
                Salvar seleção
              </button>
              <button className="cb__btn cb__btn--primary" onClick={handleAcceptAll}>
                Aceitar todos
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
